function _confirmDestructive(actionLabel){
  if(!confirm(actionLabel+'\n\nこの操作は取り消せません。本当に実行しますか?')) return false;
  var ans = prompt('確認のため "DELETE" と入力してください\n（キャンセルすると中止）', '');
  if(ans !== 'DELETE'){
    alert('入力が一致しないため中止しました');
    return false;
  }
  return true;
}

